import React from 'react';

const MovieCard = ({ movie, variant = 'poster' }) => {
  if (variant === 'wide') {
    return (
      <div className="flex-none w-72 group cursor-pointer">
        <div className="relative rounded-xl overflow-hidden bg-surface-container aspect-video">
          <img 
            className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" 
            src={movie.poster || movie.backdrop || "https://lh3.googleusercontent.com/aida-public/AB6AXuA454BDxCXx-2gziLt1-YhgOp-i_yQw8rUP2u1iJtFwEUDk42Q9hEccahgm396vYTyqTUM9EzpRuDCjQ_q0HOkyiRlLElTnJmUWeyN5hOvEonFVgxt7nbEuaDbmDJLQdgdt8rpbiq-GFG_8D2sTTTsL9J_aCS6ofagmlPZ1CykOlDjPI2LL8qUIE-UCmnkra7uU8vLckFzr1hcpRdFANTRus26jOS1TgrFJuQMlwoMp2pT5GYxLrKAcKJhhouCqV-IYPsKfo9EYIF4A"} 
            alt={movie.title}
          />
          <div className="absolute bottom-0 left-0 right-0 h-1 bg-surface-variant">
            <div className="h-full bg-primary-container w-[65%]"></div>
          </div>
          <div className="absolute top-2 right-2">
            <span className="bg-surface/80 backdrop-blur-md px-2 py-0.5 rounded text-[10px] font-bold text-secondary uppercase">
               {Math.round(movie.similarity * 100 || 92)}% MATCH
            </span>
          </div>
        </div>
        <div className="mt-3">
          <h3 className="font-bold text-sm text-on-surface">{movie.title}</h3>
          <p className="text-xs text-neutral-500 mt-1">S1:E4 • 12m left</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex-none w-52 group">
      <div className="relative aspect-[2/3] rounded-xl overflow-hidden bg-surface-container shadow-2xl transition-all duration-300 group-hover:translate-y-[-8px]">
        <img 
          className="w-full h-full object-cover" 
          src={movie.poster || "https://lh3.googleusercontent.com/aida-public/AB6AXuAfjgjyDWP1tONNBiYUzW6EP4WCY1ZBK28bk_MNjdzIgVsvAMJqpbODaSZpZFNrehbK2M-09uf7IIjWVJAxLbSpAkv8HbU2FjcxzRJ5YSjr9r7LLXrVn3HZ_p0PmCBEbePOcLzWKIg-wyyRTYVyXmZV3udKaUacQfxlQvWj3lnJ5dLMuMYH834WPKeAh1EafIy7NfJXN8v8DasxcbnqG5CMBbimdELX9jWK1Cc0rMESZntVxFzQ5z-Ew42h2X3g4migDPM_3mEY761n"} 
          alt={movie.title}
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex flex-col justify-end p-4">
          <div className="bg-tertiary-container/90 backdrop-blur-sm rounded-lg p-3 transform translate-y-4 group-hover:translate-y-0 transition-transform">
            <p className="text-[10px] font-bold text-on-tertiary-container uppercase tracking-tighter mb-1">AI Insight</p>
            <p className="text-[11px] leading-tight text-white/90">
              Matches your preference for '{movie.genres?.[0] || 'unconventional protagonistas'}' found in your recent history.
            </p>
          </div>
        </div>
      </div>
      <div className="mt-4">
        <h4 className="font-bold text-sm group-hover:text-primary transition-colors text-on-surface">{movie.title}</h4>
        <div className="flex items-center gap-2 mt-1">
          <span className="text-[10px] font-bold text-secondary-fixed-dim uppercase">{Math.round(movie.similarity * 100 || 99)}% MATCH</span>
          <span className="text-[10px] text-neutral-500">{movie.year || '2023'}</span>
        </div>
      </div>
    </div>
  );
};

export default MovieCard;
